INSERT INTO documents
(id,title,document_type,document_number,issue_date,effective_date,expired_date,organization,signer,status,version,category,risk,views,tags,abstract,full_text) VALUES
('DOC-2569-014','ระเบียบมหาวิทยาลัยราชภัฏพิบูลสงคราม ว่าด้วยการจัดซื้อจัดจ้างและการบริหารพัสดุ (ฉบับที่ 2) พ.ศ. 2569','ระเบียบ','รบ.014/2569','2026-05-12','2026-06-01',NULL,'กองคลัง','อธิการบดี','active','2.0','การเงินและพัสดุ','medium',1284,'["จัดซื้อจัดจ้าง","พัสดุ","งบประมาณ","e-bidding"]','ปรับปรุงหลักเกณฑ์และวิธีการจัดซื้อจัดจ้างให้สอดคล้องกับ พ.ร.บ. การจัดซื้อจัดจ้างฯ พ.ศ. 2560 เพิ่มวงเงินวิธีเฉพาะเจาะจงและกำหนดบทบาทคณะกรรมการ','ระเบียบนี้ปรับปรุงหลักเกณฑ์การจัดซื้อจัดจ้าง เพิ่มวงเงินวิธีเฉพาะเจาะจงเป็นไม่เกิน 500,000 บาท กำหนดให้กองคลังถือปฏิบัติ'),
('DOC-2568-009','ระเบียบมหาวิทยาลัยราชภัฏพิบูลสงคราม ว่าด้วยการจัดซื้อจัดจ้างและการบริหารพัสดุ พ.ศ. 2568','ระเบียบ','รบ.009/2568','2025-03-20','2025-04-15','2026-05-31','กองคลัง','อธิการบดี','amended','1.0','การเงินและพัสดุ','low',842,'["จัดซื้อจัดจ้าง","พัสดุ"]','ระเบียบฉบับเดิมว่าด้วยการจัดซื้อจัดจ้าง กำหนดวงเงินวิธีเฉพาะเจาะจงไม่เกิน 100,000 บาท ถูกแก้ไขเพิ่มเติมโดยฉบับที่ 2 พ.ศ. 2569','ระเบียบฉบับเดิม วงเงินวิธีเฉพาะเจาะจงไม่เกิน 100,000 บาท'),
('DOC-2569-021','ประกาศมหาวิทยาลัย เรื่อง หลักเกณฑ์การเบิกจ่ายค่าใช้จ่ายในการจัดประชุมและสัมมนา พ.ศ. 2569','ประกาศ','ปก.021/2569','2026-06-05','2026-07-01',NULL,'กองคลัง','รองอธิการบดีฝ่ายบริหาร','draft','1.0','การเงินและพัสดุ','high',233,'["เบิกจ่าย","ประชุม","สัมมนา","งบประมาณ"]','กำหนดอัตราและหลักเกณฑ์การเบิกจ่ายค่าอาหาร ค่าที่พัก และค่าตอบแทนวิทยากร อยู่ระหว่างการพิจารณาของคณะกรรมการ','หลักเกณฑ์การเบิกจ่ายค่าอาหาร ค่าที่พัก ค่าตอบแทนวิทยากร'),
('DOC-2569-007','ข้อบังคับมหาวิทยาลัย ว่าด้วยการประชุมสภามหาวิทยาลัย พ.ศ. 2569','ข้อบังคับ','ขบ.007/2569','2026-02-10','2026-03-01',NULL,'สำนักงานสภามหาวิทยาลัย','นายกสภามหาวิทยาลัย','active','1.0','การบริหารและธรรมาภิบาล','low',567,'["สภามหาวิทยาลัย","การประชุม","องค์ประชุม"]','กำหนดองค์ประชุม วาระการประชุม การลงมติ และการบันทึกรายงานการประชุมสภามหาวิทยาลัย','องค์ประชุมไม่น้อยกว่ากึ่งหนึ่ง การลงมติด้วยเสียงข้างมาก'),
('DOC-2569-031','คำสั่งมหาวิทยาลัย เรื่อง แต่งตั้งคณะกรรมการขับเคลื่อนยุทธศาสตร์ความเป็นสากล (Internationalization)','คำสั่ง','คส.031/2569','2026-06-15','2026-06-15',NULL,'กองวิเทศสัมพันธ์','อธิการบดี','active','1.0','นโยบายและยุทธศาสตร์','low',198,'["ความเป็นสากล","ยุทธศาสตร์","นักศึกษาต่างชาติ","Kenya Sandbox"]','แต่งตั้งคณะกรรมการเพื่อขับเคลื่อนนโยบายความเป็นสากล รวมถึงโครงการ Kenya Sandbox และความร่วมมือระหว่างประเทศ','แต่งตั้งคณะกรรมการขับเคลื่อนความเป็นสากล โครงการ Kenya Sandbox'),
('DOC-2569-018','ขอบเขตของงาน (TOR) โครงการพัฒนาระบบสารสนเทศเพื่อการบริหารเอกสารอัจฉริยะ','TOR','TOR.018/2569','2026-04-28','2026-05-15',NULL,'สำนักวิทยบริการและเทคโนโลยีสารสนเทศ','ผู้อำนวยการสำนักวิทยบริการฯ','active','1.0','เทคโนโลยีสารสนเทศ','high',412,'["TOR","ระบบสารสนเทศ","จัดซื้อจัดจ้าง","AI"]','กำหนดคุณลักษณะเฉพาะของระบบบริหารเอกสาร วงเงิน 4,500,000 บาท ระยะเวลาดำเนินการ 180 วัน พร้อมเงื่อนไขการรับประกัน','คุณลักษณะเฉพาะระบบบริหารเอกสาร วงเงิน 4,500,000 บาท ระยะเวลา 180 วัน'),
('DOC-2567-045','ประกาศมหาวิทยาลัย เรื่อง แนวปฏิบัติการรับนักศึกษาต่างชาติ พ.ศ. 2567','ประกาศ','ปก.045/2567','2024-08-01','2024-09-01','2026-01-01','กองวิเทศสัมพันธ์','รองอธิการบดีฝ่ายวิชาการ','cancelled','1.0','นโยบายและยุทธศาสตร์','medium',756,'["นักศึกษาต่างชาติ","รับสมัคร","วีซ่า"]','แนวปฏิบัติการรับและดูแลนักศึกษาต่างชาติ ถูกยกเลิกและแทนที่ด้วยประกาศฉบับ พ.ศ. 2569','แนวปฏิบัติการรับนักศึกษาต่างชาติ ถูกยกเลิก'),
('DOC-2566-012','แผนยุทธศาสตร์มหาวิทยาลัยราชภัฏพิบูลสงคราม ระยะ 5 ปี (พ.ศ. 2566–2570)','นโยบาย','ผย.012/2566','2023-01-15','2023-01-15',NULL,'กองนโยบายและแผน','สภามหาวิทยาลัย','active','1.0','นโยบายและยุทธศาสตร์','low',1567,'["ยุทธศาสตร์","แผน","นโยบาย"]','เอกสารแม่บทกำหนดทิศทางและเป้าหมายเชิงยุทธศาสตร์ของมหาวิทยาลัยเป็นกรอบให้แก่ระเบียบ ประกาศ และคำสั่งที่เกี่ยวข้อง','แผนยุทธศาสตร์ระยะ 5 ปี เป็นเอกสารแม่บท');
